+bool ConnectionGraph::is_mem_read_only_string_intrinsic(Node* n) {
+  uint op = n->Opcode();
+  if (op == Op_AryEq || op == Op_CountPositives ||
+    op == Op_StrComp || op == Op_StrEquals ||
+    op == Op_StrIndexOf || op == Op_StrIndexOfChar) {
+      return true;
+    }
+  return false;
+}
